// scripts/submit-indexnow.mjs
//
// Submits all URLs in the sitemap to IndexNow (api.indexnow.org).
// IndexNow is a free indexing API by Microsoft Bing. It instantly
// notifies Bing (and via Bing: DuckDuckGo, Yahoo, Yandex, Naver,
// Seznam, and teilweise.co) of new or changed URLs.
//
// Required: the IndexNow API key must be at
// https://<host>/<key>.txt (so Bing can verify ownership).
// The key is generated by the build pipeline and placed in /public/.
//
// Usage:
//   node scripts/submit-indexnow.mjs https://signupdoggy.pages.dev
//
// The script reads the sitemap, extracts all <loc> URLs, and POSTs
// them to the IndexNow API in batches of 10,000 (the API limit).

import { readFile } from 'node:fs/promises';
import { fileURLToPath } from 'node:url';
import { dirname, resolve, join } from 'node:path';
import { readdirSync } from 'node:fs';

const __filename = fileURLToPath(import.meta.url);
const __dirname = dirname(__filename);
const APP_ROOT = resolve(__dirname, '..');
const DIST = resolve(APP_ROOT, 'dist');

const HOST = process.argv[2] || process.env.SITE_URL || 'https://signupdoggy.pages.dev';

async function loadSitemapUrls() {
  const sitemapPath = join(DIST, 'sitemap.xml');
  const text = await readFile(sitemapPath, 'utf8');
  const urls = [];
  const re = /<loc>([^<]+)<\/loc>/g;
  let m;
  while ((m = re.exec(text)) !== null) urls.push(m[1]);
  return urls;
}

async function findIndexNowKey() {
  // The key is a UUID placed at public/<uuid>.txt.
  // Look for it in dist/.
  const files = readdirSync(DIST);
  const keyFile = files.find(f => /^[0-9a-f]{32}\.txt$/.test(f));
  if (!keyFile) {
    throw new Error('No IndexNow key file found in dist/. Run the build first.');
  }
  return keyFile.replace('.txt', '');
}

async function submit(urls, key) {
  // IndexNow API: POST https://api.indexnow.org/indexnow
  // Body: { host, key, keyLocation, urlList[] }
  const endpoint = 'https://api.indexnow.org/indexnow';
  const body = {
    host: HOST.replace(/^https?:\/\//, ''),
    key,
    keyLocation: `${HOST}/${key}.txt`,
    urlList: urls,
  };
  const res = await fetch(endpoint, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json; charset=utf-8' },
    body: JSON.stringify(body),
  });
  return { status: res.status, body: await res.text() };
}

async function main() {
  const urls = await loadSitemapUrls();
  const key = await findIndexNowKey();
  console.log(`[indexnow] ${urls.length} URLs from sitemap`);
  console.log(`[indexnow] key=${key} host=${HOST}`);

  // Verify the key file is reachable (Bing checks this).
  const keyCheck = await fetch(`${HOST}/${key}.txt`);
  if (!keyCheck.ok) {
    console.warn(`[indexnow] WARNING: ${HOST}/${key}.txt returned ${keyCheck.status}. Make sure the key file is deployed.`);
  } else {
    console.log(`[indexnow] Key file reachable: ${keyCheck.status}`);
  }

  // IndexNow accepts up to 10,000 URLs per request.
  const batchSize = 10000;
  let submitted = 0;
  for (let i = 0; i < urls.length; i += batchSize) {
    const batch = urls.slice(i, i + batchSize);
    const result = await submit(batch, key);
    console.log(`[indexnow] batch ${Math.floor(i / batchSize) + 1}: status=${result.status} body=${result.body.slice(0, 200)}`);
    submitted += batch.length;
  }
  console.log(`[indexnow] submitted ${submitted} URLs`);
}

main().catch((e) => {
  console.error('[indexnow] failed:', e.message);
  process.exit(1);
});
